import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const Navbar = () => {
    const { user, logout, isAdmin, isSeller } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const getRoleBadge = (role) => {
        switch(role) {
            case 'admin': return '👑 Админ';
            case 'seller': return '🏪 Продавец';
            case 'user': return '👤 Пользователь';
            default: return '';
        }
    };

    return (
        <nav style={styles.nav}>
            <div style={styles.logo}>Магазин</div>
            <div style={styles.links}>
                {user ? (
                    <>
                        {/* ✅ Отображаем роль */}
                        <span style={styles.roleBadge}>{getRoleBadge(user.role)}</span>
                        <span style={styles.username}>👤 {user.username}</span>

                        {/* ✅ Кнопка управления пользователями (только админ) */}
                        {isAdmin && (
                            <Link to="/admin/users" style={styles.adminLink}>
                                👥 Пользователи
                            </Link>
                        )}

                        <button onClick={handleLogout} style={styles.button}>
                            Выйти
                        </button>
                    </>
                ) : (
                    <>
                        <Link to="/login" style={styles.link}>Войти</Link>
                        <Link to="/register" style={styles.link}>Регистрация</Link>
                    </>
                )}
            </div>
        </nav>
    );
};

const styles = {
    nav: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '15px 30px',
        backgroundColor: '#333',
        color: 'white',
    },
    logo: { fontSize: '20px', fontWeight: 'bold' },
    links: { display: 'flex', gap: '15px', alignItems: 'center' },
    link: { color: 'white', textDecoration: 'none' },
    username: { marginRight: '10px' },
    roleBadge: {
        backgroundColor: '#4CAF50',
        padding: '4px 10px',
        borderRadius: '4px',
        fontSize: '12px',
        marginRight: '10px',
    },
    adminLink: {
        color: '#ffcc00',
        textDecoration: 'none',
        marginRight: '10px',
        fontWeight: 'bold',
    },
    button: {
        padding: '8px 16px',
        cursor: 'pointer',
        backgroundColor: '#ff4444',
        color: 'white',
        border: 'none',
        borderRadius: '4px',
    },
};

export default Navbar;
